const QUESTIONS_CISA_C3 = [
{ id:20441, domain:3, level:1, question:"What does SDLC stand for in the context of information systems development?", options:["Software Design and Lifecycle Control","System Development Life Cycle","Structured Development and Launch Cycle","Software Deployment and Licensing Compliance"], correct:1, explanation:"SDLC stands for System Development Life Cycle, which is the structured process used to plan, create, test, and deploy an information system." },
{ id:20442, domain:3, level:1, question:"Which SDLC phase involves gathering and documenting what a new system must do?", options:["Design","Testing","Requirements analysis","Maintenance"], correct:2, explanation:"The requirements analysis phase involves identifying, documenting, and agreeing on the functional and non-functional requirements the new system must satisfy." },
{ id:20443, domain:3, level:1, question:"In the waterfall development methodology, phases are completed:", options:["Sequentially with each phase completed before the next begins","Simultaneously by multiple teams","In random order based on priority","Iteratively in short cycles"], correct:0, explanation:"The waterfall methodology follows a sequential, linear process where each phase (requirements, design, development, testing, deployment) must be fully completed before the next begins." },
{ id:20444, domain:3, level:1, question:"What is the PRIMARY purpose of a feasibility study in system acquisition?", options:["To determine whether a proposed system solution is viable and justified","To train end users on the new system","To design the system architecture","To write the technical specifications"], correct:0, explanation:"A feasibility study evaluates whether a proposed system solution is technically possible, economically justified, legally compliant, and operationally practical before committing resources." },
{ id:20445, domain:3, level:1, question:"Which type of feasibility assesses whether the organization has the financial resources to develop and operate a proposed system?", options:["Technical feasibility","Operational feasibility","Economic feasibility","Schedule feasibility"], correct:2, explanation:"Economic feasibility (also called financial feasibility) assesses whether the expected benefits of a proposed system justify the costs of development, implementation, and ongoing operation." },
{ id:20446, domain:3, level:1, question:"What is a 'Request for Proposal' (RFP) used for in system acquisition?", options:["To request budget approval from the board","To invite vendors to propose solutions that meet defined requirements","To formally accept a delivered system","To document system test results"], correct:1, explanation:"An RFP is issued to potential vendors to invite them to propose their solutions, pricing, and approach for meeting the organization's defined system requirements." },
{ id:20447, domain:3, level:1, question:"Which application control type is designed to ensure that data entered into a system is accurate and complete?", options:["Input controls","Output controls","Processing controls","Audit trail controls"], correct:0, explanation:"Input controls are designed to ensure that data entering a system is authorized, accurate, complete, and in the correct format before processing occurs." },
{ id:20448, domain:3, level:1, question:"What is 'unit testing' in software development?", options:["Testing the entire system end-to-end","Testing by end users in a production-like environment","Testing system performance under load","Testing individual program modules or components in isolation"], correct:3, explanation:"Unit testing involves testing individual modules, functions, or components of software in isolation to verify that each unit performs as designed." },
{ id:20449, domain:3, level:1, question:"What is the purpose of User Acceptance Testing (UAT)?", options:["To test system performance under peak load","To check for security vulnerabilities","To verify that the system meets the business requirements defined by the users","To test individual code modules"], correct:2, explanation:"UAT is the final testing phase where end users validate that the system meets their business requirements and is ready for production use." },
{ id:20450, domain:3, level:1, question:"Which term describes the process of moving data from a legacy system into a new system?", options:["System integration","Parallel processing","Change management","Data conversion/migration"], correct:3, explanation:"Data conversion or data migration is the process of extracting data from existing systems, transforming it as needed, and loading it into the new system." },
{ id:20451, domain:3, level:1, question:"What is a 'change management' process in IT primarily designed to do?", options:["Manage employee resistance to organizational change","Replace the system development life cycle","Eliminate the need for testing","Ensure that changes to IT systems are assessed, approved, and implemented in a controlled manner"], correct:3, explanation:"IT change management ensures that modifications to systems, infrastructure, and applications are formally requested, assessed for risk, approved, tested, and implemented in a controlled way to minimize disruption." },
{ id:20452, domain:3, level:1, question:"Which development methodology uses short iterative cycles called 'sprints' to deliver working software incrementally?", options:["Waterfall","PRINCE2","Scrum/Agile","RAD"], correct:2, explanation:"Scrum is an Agile framework that uses fixed-length iterations called sprints (typically 2-4 weeks) to deliver working, potentially shippable software increments." },
{ id:20453, domain:3, level:1, question:"What does 'version control' in software development primarily manage?", options:["Managing software license versions","Managing software project budgets","Tracking and managing changes to source code over time","Controlling the number of software users"], correct:2, explanation:"Version control (also called source control) tracks and manages changes to source code, enabling teams to maintain history, coordinate changes, and revert to prior versions if needed." },
{ id:20454, domain:3, level:1, question:"Which of the following BEST describes 'regression testing'?", options:["Re-testing previously working functionality after changes to ensure nothing has broken","Testing new features for the first time","Testing system behavior under extreme loads","Testing system recovery after failures"], correct:0, explanation:"Regression testing verifies that existing functionality still works correctly after new code changes, bug fixes, or enhancements have been made to the system." },
{ id:20455, domain:3, level:1, question:"In project management, what does a 'project charter' formally establish?", options:["The detailed project budget","The technical architecture of the system","The testing strategy for the project","The project's existence, objectives, scope, and the authority of the project manager"], correct:3, explanation:"A project charter is the document that formally authorizes the project, defines its objectives and high-level scope, and grants the project manager authority to apply organizational resources." },
{ id:20456, domain:3, level:1, question:"What is the PRIMARY risk associated with a 'build vs. buy' decision when organizations choose to build custom software?", options:["Vendor lock-in","Loss of proprietary information","Higher development cost, time, and risk compared to purchasing a proven solution","Reduced system functionality"], correct:2, explanation:"Building custom software carries higher cost, schedule, and quality risk compared to purchasing proven commercial off-the-shelf software, and organizations may underestimate these risks." },
{ id:20457, domain:3, level:1, question:"Which testing type examines how different system components work together?", options:["Unit testing","Integration testing","Acceptance testing","Stress testing"], correct:1, explanation:"Integration testing verifies that separate modules or components of a system interact correctly with each other, checking interfaces and data flows between components." },
{ id:20458, domain:3, level:1, question:"What is 'parallel running' in the context of system implementation?", options:["Running two development teams simultaneously","Testing a system in parallel with production","Running the same code on multiple servers","Operating both the old and new systems simultaneously to compare outputs during transition"], correct:3, explanation:"Parallel running operates the old and new systems simultaneously, comparing their outputs to ensure the new system produces correct results before fully switching over." },
{ id:20459, domain:3, level:1, question:"Which OWASP resource is most commonly referenced for application security risks?", options:["OWASP Testing Guide","OWASP SAMM","OWASP Top Ten","OWASP Code Review Guide"], correct:2, explanation:"The OWASP Top Ten is the most widely referenced list of the ten most critical web application security risks, used as a baseline for application security awareness and testing." },
{ id:20460, domain:3, level:1, question:"What is 'post-implementation review' primarily intended to assess?", options:["Whether the project manager performed well","Whether the implemented system has achieved its intended objectives and delivered expected benefits","Whether the budget was approved correctly","Whether the developers followed coding standards"], correct:1, explanation:"A post-implementation review (PIR) evaluates whether the deployed system has met its original objectives, delivered expected benefits, and identifies lessons learned for future projects." },
{ id:20461, domain:3, level:1, question:"Which document formally records and tracks defects discovered during software testing?", options:["Change request form","Project charter","Requirements traceability matrix","Defect/bug tracking log"], correct:3, explanation:"A defect or bug tracking log records all defects discovered during testing, including their severity, status, and resolution, enabling systematic management of software quality issues." },
{ id:20462, domain:3, level:1, question:"What is the purpose of an 'audit trail' in an application system?", options:["To slow down transaction processing","To prevent users from accessing the system","To provide a chronological record of system activities for accountability and review","To replace backup procedures"], correct:2, explanation:"An audit trail is a chronological record of system activities, transactions, and user actions that enables accountability, reconstruction of events, and detection of unauthorized activities." },
{ id:20463, domain:3, level:1, question:"In software quality assurance (SQA), what is the PRIMARY goal?", options:["To reduce development team size","To accelerate software deployment","To eliminate all documentation requirements","To ensure the software product meets defined quality standards and requirements"], correct:3, explanation:"Software quality assurance ensures that software products and processes conform to defined quality standards, requirements, and procedures throughout the development lifecycle." },
{ id:20464, domain:3, level:1, question:"Which SDLC phase produces the technical blueprint specifying how the system will be built?", options:["Requirements analysis","Testing","System design","Maintenance"], correct:2, explanation:"The system design phase translates requirements into a technical blueprint, specifying system architecture, data structures, interfaces, and other technical components." },
{ id:20465, domain:3, level:1, question:"What does 'patch management' in IT primarily address?", options:["Applying security and functional updates to software and systems in a controlled manner","Managing physical infrastructure upgrades","Managing software development projects","Controlling user access to systems"], correct:0, explanation:"Patch management is the systematic process of identifying, testing, approving, and applying updates (patches) to software and systems to address security vulnerabilities and functional issues." },
{ id:20466, domain:3, level:2, question:"During an IS audit of a software development project, an auditor finds no requirements traceability matrix. What is the PRIMARY risk?", options:["The project will exceed its budget","The development team will be understaffed","Testing will be completed too quickly","Requirements may not be fully implemented or tested, leading to systems that do not meet business needs"], correct:3, explanation:"Without a requirements traceability matrix, there is no assurance that all requirements have been addressed in the design, implemented in the code, and verified through testing, creating risk of gaps." },
{ id:20467, domain:3, level:2, question:"An auditor is reviewing a software project that is significantly over budget and behind schedule. Which project management artifact BEST helps identify when these deviations occurred?", options:["Project charter","User acceptance test results","Change request log","Earned value management (EVM) reports"], correct:3, explanation:"Earned value management reports track project performance by comparing planned vs. actual cost and schedule, enabling identification of when and where deviations occurred." },
{ id:20468, domain:3, level:2, question:"Which type of input control verifies that a transaction amount falls within a predefined acceptable range?", options:["Format check","Existence check","Range/limit check","Completeness check"], correct:2, explanation:"A range or limit check validates that entered values fall within predefined minimum and maximum boundaries, preventing erroneous or fraudulent out-of-range values from being processed." },
{ id:20469, domain:3, level:2, question:"An organization is selecting a new ERP system. Which vendor evaluation criterion is MOST important from a controls perspective?", options:["The vendor's financial stability and long-term viability","The vendor's marketing reputation","The system's color scheme and interface design","The number of employees at the vendor company"], correct:0, explanation:"Vendor financial stability is critical because if the vendor fails, the organization may lose access to support, patches, and updates, creating significant operational and security risk." },
{ id:20470, domain:3, level:2, question:"What is the PRIMARY purpose of a 'code review' in secure software development?", options:["To assess developer performance","To document the system architecture","To identify security vulnerabilities, bugs, and code quality issues before deployment","To train developers on new programming languages"], correct:2, explanation:"Code review is a systematic examination of source code by other developers or security specialists to identify defects, security vulnerabilities, and deviations from coding standards before the software is deployed." },
{ id:20471, domain:3, level:2, question:"In agile development, what role is responsible for prioritizing the product backlog?", options:["Scrum Master","Development Team","Product Owner","Stakeholder committee"], correct:2, explanation:"The Product Owner is responsible for maintaining and prioritizing the product backlog, ensuring the development team works on the highest-value items first." },
{ id:20472, domain:3, level:2, question:"Which control BEST ensures the completeness of batch transaction processing?", options:["Hash totals","Output distribution lists","Segregation of duties","Encryption"], correct:0, explanation:"Hash totals are control totals calculated from non-financial fields (such as account numbers) and compared before and after processing to verify that all records in a batch have been completely and accurately processed." },
{ id:20473, domain:3, level:2, question:"An IS auditor is reviewing a system migration project. Which control is MOST important to verify data integrity during migration?", options:["Migrating data during business hours","Performing reconciliation of record counts and control totals before and after migration","Migrating data in a single large batch","Having the development team perform the migration"], correct:1, explanation:"Reconciling record counts and control totals before and after data migration is the most important control for verifying that all data was accurately and completely transferred without loss or corruption." },
{ id:20474, domain:3, level:2, question:"What is the MAIN risk of allowing developers to have access to the production environment?", options:["Developers may work too slowly","The development environment will be understaffed","Production systems will run out of storage","Developers could introduce unauthorized changes or access sensitive production data, undermining change control"], correct:3, explanation:"Developer access to production violates segregation of duties and creates risk that unauthorized changes could be introduced or sensitive data accessed outside of the controlled change management process." },
{ id:20475, domain:3, level:2, question:"Which methodology follows a spiral model that emphasizes risk analysis at each iteration?", options:["Waterfall","Agile Scrum","Spiral model","RAD"], correct:2, explanation:"The spiral model combines iterative development with systematic risk analysis, progressing through repeated cycles of planning, risk analysis, engineering, and evaluation." },
{ id:20476, domain:3, level:2, question:"What is the purpose of a 'requirements traceability matrix' (RTM)?", options:["To track project expenses","To map requirements to design elements, code, and test cases to ensure full coverage","To document meeting minutes","To manage vendor contracts"], correct:1, explanation:"An RTM traces each requirement from its origin through design, implementation, and testing, ensuring that all requirements are addressed and that all test cases are linked to specific requirements." },
{ id:20477, domain:3, level:2, question:"An IS auditor reviews a system acquisition and finds that the contract with the vendor does not include a right-to-audit clause. What is the PRIMARY risk?", options:["The vendor will charge higher prices","The contract will expire too quickly","The organization must train the vendor's staff","The organization cannot independently verify the vendor's control environment and compliance"], correct:3, explanation:"Without a right-to-audit clause, the organization cannot independently review the vendor's controls, creating reliance on vendor-provided assurances without independent verification capability." },
{ id:20478, domain:3, level:2, question:"Which software development practice involves developers integrating code changes frequently and running automated tests to detect problems early?", options:["Waterfall integration","Batch development","Continuous integration (CI)","Parallel processing"], correct:2, explanation:"Continuous integration is the practice of frequently merging developer code changes into a shared repository and running automated build and test processes to detect integration problems early." },
{ id:20479, domain:3, level:2, question:"What is the PRIMARY purpose of 'stress testing' a system?", options:["To verify individual code modules","To test how the system behaves under extreme or peak load conditions beyond normal capacity","To test user interface usability","To verify business requirements are met"], correct:1, explanation:"Stress testing evaluates how a system performs when subjected to extreme loads beyond its designed capacity, revealing failure modes, bottlenecks, and recovery behavior under extreme conditions." },
{ id:20480, domain:3, level:2, question:"An auditor is reviewing an organization's patch management process. Which finding represents the GREATEST risk?", options:["Patches are tested in a non-production environment before deployment","Patch deployment is scheduled during maintenance windows","A patch register is maintained","Critical security patches take over 90 days to be applied to production systems"], correct:3, explanation:"A 90+ day lag in applying critical security patches leaves systems exposed to known vulnerabilities for an extended period, significantly increasing the risk of exploitation." },
{ id:20481, domain:3, level:2, question:"In a waterfall SDLC, which phase directly follows the design phase?", options:["Requirements analysis","Testing","Development/coding","Deployment"], correct:2, explanation:"In the traditional waterfall model, the development or coding phase follows the design phase, translating the technical design specifications into working software code." },
{ id:20482, domain:3, level:2, question:"What is 'configuration management' in IT systems primarily concerned with?", options:["Managing user access configurations","Systematically handling changes to system configurations and maintaining records of the current state","Managing project budget allocations","Configuring network bandwidth"], correct:1, explanation:"Configuration management involves identifying, documenting, controlling, and auditing changes to system configurations to maintain system integrity and support change control processes." },
{ id:20483, domain:3, level:2, question:"Which acquisition approach involves purchasing software from an external vendor rather than building it internally?", options:["Custom development","Commercial off-the-shelf (COTS) acquisition","Insourcing","Open-source development"], correct:1, explanation:"Commercial off-the-shelf (COTS) acquisition involves purchasing existing software products from vendors rather than developing custom software, offering faster deployment but less customization." },
{ id:20484, domain:3, level:2, question:"An IS auditor finds that no independent testing was performed before a critical financial system was deployed. What is the PRIMARY concern?", options:["Development costs may be too high","The system may be too slow","User documentation may be incomplete","Defects and control weaknesses may exist in production that could lead to processing errors or fraud"], correct:3, explanation:"Without independent testing before production deployment, undetected defects and control weaknesses could cause processing errors, data integrity issues, or enable fraudulent transactions." },
{ id:20485, domain:3, level:2, question:"Which of the following is a key characteristic of the RAD (Rapid Application Development) methodology?", options:["Long planning phases with detailed upfront documentation","Strict sequential phase completion","Focus on hardware acquisition before software development","Heavy use of prototyping and user feedback to rapidly develop systems"], correct:3, explanation:"RAD emphasizes rapid prototyping, continuous user feedback, and iterative refinement to quickly develop systems, trading off some rigor for speed and user involvement." },
{ id:20486, domain:3, level:2, question:"What is the role of a 'change advisory board' (CAB) in IT change management?", options:["To approve organizational restructuring","To manage the IT project portfolio","To conduct IT security audits","To review and approve IT changes, assessing risk and ensuring proper authorization"], correct:3, explanation:"The change advisory board reviews proposed IT changes, assesses their risk and impact, and provides recommendations or approval, ensuring changes are properly controlled and authorized." },
{ id:20487, domain:3, level:2, question:"Which output control verifies that reports and system outputs are delivered only to authorized recipients?", options:["Output distribution controls","Batch totals","Range checks","Hash totals"], correct:0, explanation:"Output distribution controls ensure that system-generated reports and outputs are delivered only to authorized individuals and that sensitive output is appropriately protected during distribution." },
{ id:20488, domain:3, level:2, question:"What does 'DevOps' combine in software development and delivery?", options:["Development and operations to enable faster, more reliable software delivery through collaboration and automation","Development and security to focus on secure coding","Operations and security to manage infrastructure","Design and operations to improve system performance"], correct:0, explanation:"DevOps combines software development (Dev) and IT operations (Ops) practices, emphasizing collaboration, automation, and continuous delivery to shorten development cycles and improve deployment reliability." },
{ id:20489, domain:3, level:2, question:"An IS auditor is reviewing a COTS implementation project. Which risk is MOST unique to COTS compared to custom development?", options:["Insufficient testing","Poor documentation","Vendor dependency and the inability to modify source code to meet unique business requirements","Budget overruns"], correct:2, explanation:"COTS creates vendor dependency and limits the ability to customize the software, meaning organizations must adapt business processes to fit the software or rely on vendor-provided customization options." },
{ id:20490, domain:3, level:2, question:"Which secure development practice involves identifying potential threats to a system during the design phase?", options:["Penetration testing","Code review","Regression testing","Threat modeling"], correct:3, explanation:"Threat modeling is a structured process performed during design to proactively identify potential threats, vulnerabilities, and attack vectors so security controls can be designed into the system." },
{ id:20491, domain:3, level:2, question:"What is the PRIMARY purpose of segregating development, testing, and production environments?", options:["To reduce hardware costs","To improve system performance","To prevent unauthorized changes to production and ensure testing occurs in a controlled environment before deployment","To simplify system administration"], correct:2, explanation:"Separating environments prevents unauthorized or untested changes from entering production and ensures that testing occurs in controlled conditions that do not affect live data or system stability." },
{ id:20492, domain:3, level:2, question:"Which control is MOST effective at preventing SQL injection attacks in an application?", options:["Input length limits","Password complexity requirements","Audit logging","Parameterized queries/prepared statements"], correct:3, explanation:"Parameterized queries (prepared statements) prevent SQL injection by separating SQL code from user-supplied data, ensuring user input cannot be interpreted as SQL commands." },
{ id:20493, domain:3, level:2, question:"During a project post-implementation review, which finding is MOST significant from an IS audit perspective?", options:["The system's actual benefits are significantly below the benefits projected in the business case","The project was delivered two weeks late","One minor enhancement request was not completed","The project manager has left the organization"], correct:0, explanation:"A significant gap between projected and actual benefits indicates that the business case was overstated or the system failed to deliver expected value, which has direct accountability and governance implications." },
{ id:20494, domain:3, level:2, question:"What is 'penetration testing' in application security?", options:["Testing system performance under load","Testing data backup and recovery procedures","Testing system usability with real users","Authorized simulated attacks on a system to identify exploitable vulnerabilities"], correct:3, explanation:"Penetration testing involves authorized security professionals simulating real-world attacks to identify and exploit vulnerabilities, providing evidence of actual exploitability rather than just theoretical risk." },
{ id:20495, domain:3, level:2, question:"Which document provides a formal record of all requirements for a system, serving as the baseline for development and testing?", options:["Project charter","Change request form","System Requirements Specification (SRS)","Test plan"], correct:2, explanation:"A System Requirements Specification formally documents all functional and non-functional requirements for a system, serving as the contractual baseline between stakeholders and the development team." },
{ id:20496, domain:3, level:2, question:"In Agile projects, what is a 'sprint retrospective' designed to achieve?", options:["To demonstrate completed features to stakeholders","To plan the next sprint's work","To reflect on and improve the team's processes and practices","To review the product backlog"], correct:2, explanation:"The sprint retrospective is a recurring ceremony where the team reflects on their process, identifies what worked well and what can be improved, and makes commitments to improvement in the next sprint." },
{ id:20497, domain:3, level:2, question:"Which type of application control ensures that every transaction is assigned a unique identifier for tracking purposes?", options:["Range check","Sequence check","Completeness check","Existence check"], correct:1, explanation:"A sequence check ensures that transactions are assigned unique sequential identifiers, enabling detection of missing, duplicate, or out-of-order transactions." },
{ id:20498, domain:3, level:2, question:"An IS auditor is reviewing the system acquisition process. Which phase is MOST critical for establishing control requirements?", options:["Deployment","Post-implementation review","User training","Requirements definition"], correct:3, explanation:"Control requirements must be defined during the requirements definition phase; retrofitting controls after development is significantly more costly and less effective than designing them in from the beginning." },
{ id:20499, domain:3, level:2, question:"What is the PRIMARY purpose of a 'test plan' in software development?", options:["To document test results","To list all identified defects","To provide user training materials","To define the scope, approach, resources, and schedule for testing activities"], correct:3, explanation:"A test plan defines the testing strategy including scope, objectives, approach, resources, schedule, and criteria for test completion and success, guiding the overall testing effort." },
{ id:20500, domain:3, level:2, question:"Which risk is GREATEST when an organization migrates from a legacy system to a new system using a 'big bang' cutover approach?", options:["If the new system fails at cutover, there is no immediate fallback to the old system","Development costs are too high","Users will be insufficiently trained","The new system will not be compatible with existing hardware"], correct:0, explanation:"A big bang cutover replaces the old system completely at one point in time; if problems arise, there is no operational fallback, creating maximum risk of business disruption." },
{ id:20501, domain:3, level:1, question:"What is the purpose of a 'business case' in IS project initiation?", options:["To document the technical architecture","To list all project team members","To justify the investment by demonstrating expected costs, benefits, and risks","To define the testing approach"], correct:2, explanation:"A business case provides the rationale for a proposed investment by quantifying expected costs, benefits, risks, and strategic alignment, enabling decision-makers to approve or reject the initiative." },
{ id:20502, domain:3, level:1, question:"Which project management framework uses defined roles such as project board, project manager, and team manager?", options:["Agile Scrum","PMBOK","PRINCE2","Waterfall"], correct:2, explanation:"PRINCE2 (Projects IN Controlled Environments) defines specific roles including a project board (senior responsible owner, senior user, supplier), project manager, and team manager." },
{ id:20503, domain:3, level:1, question:"In software development, what is a 'prototype'?", options:["The final production version of the software","A preliminary working model of the system used to gather user feedback","A backup copy of the system","A detailed technical design document"], correct:1, explanation:"A prototype is an early working model of a system or feature, built to demonstrate concepts and gather user feedback before full-scale development, reducing requirements misunderstanding." },
{ id:20504, domain:3, level:1, question:"Which of the following is an example of a processing control in an application?", options:["User authentication","Output distribution list","Encryption of stored data","Edit checks that validate data during processing"], correct:3, explanation:"Processing controls, such as edit checks and validation routines, ensure that data is accurately and completely processed according to defined business rules during system execution." },
{ id:20505, domain:3, level:1, question:"What does 'scope creep' refer to in project management?", options:["A project finishing ahead of schedule","The project manager losing control of the team","Uncontrolled expansion of project scope without corresponding adjustment to resources or schedule","A reduction in project requirements"], correct:2, explanation:"Scope creep refers to the gradual, uncontrolled addition of features or requirements to a project without formal change control, increasing cost and schedule risk." },
{ id:20506, domain:3, level:1, question:"Which software testing type is performed without knowledge of the internal code structure?", options:["White-box testing","Grey-box testing","Black-box testing","Unit testing"], correct:2, explanation:"Black-box testing evaluates system functionality based only on inputs and outputs, without knowledge of the internal code structure, simulating the perspective of an end user or attacker." },
{ id:20507, domain:3, level:1, question:"What is the PRIMARY purpose of a 'service level agreement' (SLA) in system acquisition contracts?", options:["To define the software license terms","To specify measurable performance standards and remedies for non-compliance","To list all vendor employees assigned to the project","To describe the vendor's organizational structure"], correct:1, explanation:"An SLA defines measurable performance standards (availability, response time, support levels) and specifies remedies or penalties if the vendor fails to meet those standards." },
{ id:20508, domain:3, level:1, question:"In the context of IS development, what is 'white-box testing'?", options:["Testing performed by external auditors","Testing performed without any system knowledge","Testing that focuses only on user interfaces","Testing with full knowledge of the internal code structure and logic"], correct:3, explanation:"White-box testing (also called structural or glass-box testing) is performed with full knowledge of the internal code structure, enabling testers to design tests that exercise specific code paths and logic." },
{ id:20509, domain:3, level:1, question:"Which term describes software updates that fix known security vulnerabilities?", options:["Feature updates","Version upgrades","Configuration changes","Security patches"], correct:3, explanation:"Security patches are software updates specifically released to fix known security vulnerabilities, distinct from feature updates or major version upgrades." },
{ id:20510, domain:3, level:1, question:"What is the PRIMARY benefit of using a phased (staged) implementation approach?", options:["It eliminates the need for testing","It is always faster than other approaches","It reduces implementation risk by deploying in increments, allowing issues to be identified and resolved before full rollout","It requires fewer resources than other approaches"], correct:2, explanation:"Phased implementation reduces risk by deploying the system to limited groups or functionality at a time, allowing problems to be identified and resolved before full organizational deployment." },
{ id:20511, domain:3, level:1, question:"What is 'technical debt' in software development?", options:["The financial cost of software licenses","The outstanding payments to software vendors","The accumulation of shortcuts and quick fixes in code that create future maintenance burden","The cost of upgrading hardware for new software"], correct:2, explanation:"Technical debt refers to the implied cost of rework caused by choosing easy or quick solutions now instead of better approaches, which accumulate over time and increase maintenance complexity." },
{ id:20512, domain:3, level:1, question:"Which SDLC activity involves identifying what resources, time, and budget are needed for a project?", options:["Project planning","Requirements analysis","System design","Post-implementation review"], correct:0, explanation:"Project planning involves estimating and scheduling the resources, time, budget, and activities needed to successfully complete the system development or acquisition project." },
{ id:20513, domain:3, level:1, question:"What does 'PMBOK' stand for?", options:["Project Management Body of Knowledge","Program Management Best Operation Kit","Project Monitoring and Budget Overview Knowledgebase","Professional Management Business Operations Knowledge"], correct:0, explanation:"PMBOK stands for Project Management Body of Knowledge, published by PMI (Project Management Institute), providing a comprehensive framework of project management best practices and processes." },
{ id:20514, domain:3, level:1, question:"Which application security principle states that users should only be granted the minimum access necessary to perform their job functions?", options:["Defense in depth","Least privilege","Fail-safe defaults","Separation of duties"], correct:1, explanation:"The principle of least privilege requires that users, applications, and systems be granted only the minimum access rights needed to perform their specific functions, limiting the impact of breaches." },
{ id:20515, domain:3, level:1, question:"What is the purpose of a 'test environment' in system development?", options:["To store production data","To replace the development environment","To provide a controlled environment for testing software changes without affecting production","To provide user training"], correct:2, explanation:"A test environment is a controlled replica of production used exclusively for testing software changes, ensuring that tests do not impact live systems or data." },
{ id:20516, domain:3, level:2, question:"An IS auditor is reviewing an organization's SDLC process. Which finding indicates the GREATEST control weakness?", options:["Design documents are stored in a shared folder","System requirements are approved by end users and IT together","Changes to production code are made directly by developers without following the change management process","Testing is conducted in a separate environment from production"], correct:2, explanation:"Direct changes to production code by developers without change management controls eliminate key safeguards, creating serious risk of unauthorized modifications, untested changes, and loss of system integrity." },
{ id:20517, domain:3, level:2, question:"During a review of an Agile project, an IS auditor notes that there is no documented requirements specification. What is the PRIMARY audit concern?", options:["The project will be delivered late","Developers will be unmotivated","Testing will be skipped","Without formal requirements documentation, it is difficult to independently verify that the delivered system meets intended business needs or to audit completeness of implementation"], correct:3, explanation:"The absence of documented requirements makes it impossible to independently verify that the system meets intended business needs, trace requirements to test cases, or establish accountability for gaps." },
{ id:20518, domain:3, level:2, question:"Which control BEST mitigates the risk of unauthorized changes to production software?", options:["Requiring developers to document their changes","Implementing formal change control requiring independent approval and testing before production deployment","Encrypting source code","Having developers test their own code"], correct:1, explanation:"Formal change control with independent approval and pre-deployment testing is the most effective control, as it provides oversight, segregation of duties, and assurance that changes are authorized and tested." },
{ id:20519, domain:3, level:2, question:"An auditor reviewing a data migration project finds that a validation report shows 5% of records failed migration. What should the auditor recommend FIRST?", options:["Proceed with deployment since 95% migrated successfully","Delete the failed records from both systems","Investigate the root cause of failures, assess the impact on business operations, and require resolution before going live","Migrate the failed records manually without validation"], correct:2, explanation:"Any migration failures require root cause investigation and impact assessment before go-live; proceeding without resolving known data integrity issues creates unacceptable risk to business operations." },
{ id:20520, domain:3, level:2, question:"What is the MOST significant risk when security testing is performed only at the end of the SDLC?", options:["Security testing takes too long","The testing team is not available","Security vulnerabilities discovered late are expensive to fix and may delay deployment, or be accepted without remediation due to schedule pressure","Security testing is only effective at the end"], correct:2, explanation:"Discovering security vulnerabilities at the end of development is costly to remediate, and schedule pressure may lead to shortcuts or risk acceptance; security testing should be integrated throughout the SDLC." },
{ id:20521, domain:3, level:2, question:"An IS auditor is reviewing a software procurement process. Which control is MOST important during vendor due diligence?", options:["Checking the vendor's website design","Verifying the number of vendor employees","Assessing the vendor's financial stability, security practices, and support capability","Reviewing vendor advertising materials"], correct:2, explanation:"Vendor due diligence should assess financial stability (to ensure long-term support), security practices (to assess supply chain risk), and support capability (to ensure ongoing maintenance)." },
{ id:20522, domain:3, level:2, question:"Which type of testing specifically evaluates an application's ability to handle concurrent users without performance degradation?", options:["Regression testing","Security testing","Load/performance testing","Unit testing"], correct:2, explanation:"Load and performance testing evaluates how the system performs under expected concurrent user loads and identifies performance bottlenecks before production deployment." },
{ id:20523, domain:3, level:2, question:"In project management, what is 'earned value management' (EVM) used to measure?", options:["The financial value delivered to end users","Developer productivity","Project schedule and cost performance by comparing planned vs. actual work completed","Vendor payment schedules"], correct:2, explanation:"EVM measures project performance by integrating scope, schedule, and cost, comparing the value of work planned with work actually completed and actual costs incurred." },
{ id:20524, domain:3, level:2, question:"An IS auditor finds that end users were not involved in system testing before a new financial application went live. What is the PRIMARY risk this creates?", options:["The project will cost more than planned","Documentation will be incomplete","The system will have too many features","The system may not meet user needs, and critical functional or usability issues may not be discovered until after deployment"], correct:3, explanation:"Without user acceptance testing, the system may fail to meet actual business needs, have usability issues, or not support key business processes, only discovered after costly production deployment." },
{ id:20525, domain:3, level:2, question:"Which element of configuration management is responsible for identifying and recording all components and their relationships?", options:["Change control","Status accounting","Configuration audit","Configuration identification"], correct:3, explanation:"Configuration identification is the process of selecting and defining configuration items, their components, and relationships, providing the baseline for all other configuration management activities." },
{ id:20526, domain:3, level:2, question:"What is a 'known error' in IT service management, and why is it important during system implementation?", options:["An error that has been identified and has a documented workaround or solution","An error only found in testing environments","An error caused by users","An error that cannot be fixed"], correct:0, explanation:"A known error is a problem that has a documented root cause and a workaround or fix; tracking known errors during implementation ensures all identified issues are documented, monitored, and addressed before go-live." },
{ id:20527, domain:3, level:2, question:"Which practice BEST ensures that software code meets security standards before deployment?", options:["Having developers peer-review each other's code","Relying on penetration testing after deployment","Implementing automated static application security testing (SAST) tools in the development pipeline","Requiring developers to attend annual security training"], correct:2, explanation:"Automated SAST tools analyze source code for security vulnerabilities during development, providing immediate feedback and systematic coverage that manual peer review may miss." },
{ id:20528, domain:3, level:2, question:"An IS auditor reviews an outsourced software development contract and finds no provisions for source code escrow. What is the PRIMARY risk?", options:["The vendor will charge higher rates","The organization cannot resell the software","The software will not be updated","If the vendor goes out of business, the organization may lose access to the source code and be unable to maintain or enhance the system"], correct:3, explanation:"Without source code escrow, vendor failure or contract termination could leave the organization unable to access source code, making maintenance, enhancement, or migration impossible." },
{ id:20529, domain:3, level:2, question:"Which Agile concept represents the team's commitment to complete a set of work within a fixed time period?", options:["Sprint goal","Epic","Product backlog","User story"], correct:0, explanation:"The sprint goal represents the team's commitment—what they aim to deliver by the end of the sprint—providing focus and a basis for evaluating sprint success." },
{ id:20530, domain:3, level:2, question:"What is the MAIN purpose of a 'checkpoint review' in project management?", options:["To check developer timesheets","To assess project status at defined milestones and make go/no-go decisions before proceeding","To review the final project deliverables","To conduct performance appraisals for project team members"], correct:1, explanation:"Checkpoint reviews are formal assessments at predefined project milestones that evaluate progress, quality, and risk, enabling management to make informed go/no-go decisions before committing further resources." },
{ id:20531, domain:3, level:3, question:"An IS auditor is reviewing an Agile development environment and finds that testing is performed by developers within the same sprint. What compensating control would BEST address the independence concern?", options:["Require developers to document test results","Have the Scrum Master review all test results","Increase the sprint length","Implement automated testing with results independently reviewed, and require separate UAT by business stakeholders before deployment"], correct:3, explanation:"Automated testing with independent result review combined with business-led UAT provides the independence needed to compensate for the lack of a separate QA team within Agile sprints." },
{ id:20532, domain:3, level:3, question:"During a review of a critical system implementation, an IS auditor finds that the organization skipped parallel running due to time pressure. Which risk is MOST important to communicate to management?", options:["The project will be more expensive","Without parallel running, there is no validation that the new system produces identical results to the legacy system, creating undetected processing error risk in production","The legacy system cannot be decommissioned","Users will not accept the new system"], correct:1, explanation:"Parallel running is the primary control for detecting differences between old and new systems; bypassing it means processing errors in the new system may not be detected until they cause business impact." },
{ id:20533, domain:3, level:3, question:"An IS auditor identifies that an organization's change management process classifies all changes as 'standard' to avoid the review process. What is the MOST significant risk?", options:["Standard changes create too much documentation","The change advisory board will have nothing to do","Standard changes may be performed too quickly","Improperly classifying changes circumvents the review and approval controls designed to prevent unauthorized, untested, or risky changes from entering production"], correct:3, explanation:"Misclassifying changes as standard to avoid review is a control circumvention that eliminates oversight and approval, creating high risk of unauthorized, risky, or untested changes being implemented in production." },
{ id:20534, domain:3, level:3, question:"An organization is implementing a new financial system using an Agile methodology. An IS auditor is concerned about audit trail completeness. What is the MOST effective audit recommendation?", options:["Switch to waterfall methodology","Require that every sprint explicitly includes audit trail and logging requirements as part of the definition of done, verified through automated testing","Add audit trail requirements at the end of the project","Have auditors attend all sprint ceremonies"], correct:1, explanation:"Including audit trail requirements in the definition of done for every sprint ensures logging is built into every feature from the start and verified through testing, rather than retrofitted at project end." },
{ id:20535, domain:3, level:3, question:"A post-implementation review of a large ERP implementation reveals that 40% of planned benefits have not been realized two years after go-live. What should the IS auditor PRIMARILY investigate?", options:["Whether the project manager should be disciplined","Whether benefits realization responsibilities were assigned, tracked, and whether process changes needed to realize benefits were implemented","Whether the ERP vendor delivered the contracted software","Whether the project was delivered on time"], correct:1, explanation:"Benefits realization failures typically result from inadequate governance (no accountability for benefits), insufficient process change, or inadequate user adoption—the auditor should assess whether a benefits realization management process exists and was followed." },
{ id:20536, domain:3, level:3, question:"An IS auditor reviews an organization's DevOps pipeline and finds that automated security scans are configured but their results are never reviewed or acted upon. What is the PRIMARY risk?", options:["The pipeline will slow down","The scan reports take up too much storage","Developers will be frustrated by false positives","Security vulnerabilities are being identified but not remediated, providing only an illusion of security control while actual risk accumulates"], correct:3, explanation:"Automated security tools only provide value if their findings are reviewed and actioned; unreviewed scan results mean vulnerabilities accumulate in production, creating false assurance while actual security risk grows." },
{ id:20537, domain:3, level:3, question:"An IS auditor evaluating an outsourced application development contract finds that acceptance criteria are not defined. What is the MOST significant risk?", options:["Without defined acceptance criteria, the organization has no contractual basis for rejecting deficient deliverables, potentially accepting software that does not meet requirements","The vendor will deliver the software late","The software will cost more than planned","The vendor will use unapproved programming languages"], correct:0, explanation:"Undefined acceptance criteria eliminate the organization's ability to formally reject deliverables that don't meet requirements, creating risk of accepting and paying for non-compliant software with no contractual remedy." },
{ id:20538, domain:3, level:3, question:"During a review of a software development project, an IS auditor finds that developers are committing code directly to the main production branch without peer review or automated testing. What is the MOST appropriate finding?", options:["Developers are too productive","This practice eliminates key quality and security gates, creating high risk of defects and vulnerabilities reaching production without detection","Code reviews take too long","Automated testing is not always necessary"], correct:1, explanation:"Direct commits to the production branch without peer review or automated testing bypass critical quality controls, allowing defects, security vulnerabilities, and unauthorized changes to reach production unchecked." },
{ id:20539, domain:3, level:3, question:"An organization is considering purchasing a COTS application that requires significant customization to meet business needs. What is the PRIMARY risk the IS auditor should highlight?", options:["COTS applications always cost more than custom development","Extensive customization undermines COTS benefits, increases costs and complexity, creates upgrade difficulty, and may result in an application that is neither a good COTS fit nor a true custom solution","COTS applications are always less secure than custom software","The vendor will not provide training"], correct:1, explanation:"Heavy customization of COTS software negates its primary benefits (lower cost, proven functionality, vendor support), creates upgrade compatibility problems, increases maintenance burden, and often results in poor outcomes." },
{ id:20540, domain:3, level:3, question:"An IS auditor is reviewing a critical system that was implemented two years ago and has never had a post-implementation review. What is the MOST significant concern?", options:["The project manager should be reviewed","Without a PIR, the organization has no systematic assessment of whether benefits were realized, lessons were learned, or residual risks were addressed, reducing the quality of IS governance","Documentation may be outdated","The system may need to be replaced"], correct:1, explanation:"The absence of a PIR means the organization cannot assess benefit realization, identify unresolved implementation issues, or capture lessons for future projects—representing a governance gap in the IS investment lifecycle." },
{ id:20541, domain:3, level:3, question:"An IS auditor finds that an organization's vendor selection process did not include evaluation of the vendor's security certifications or SOC reports. What is the PRIMARY risk?", options:["The vendor may charge higher prices in future","The organization may have acquired a system or service with inadequate security controls, exposing organizational data and systems to unassessed supply chain risk","The vendor selection took too long","The vendor's support team may be too small"], correct:1, explanation:"Omitting security assessment during vendor selection means the organization may have unknowingly introduced supply chain risk through a vendor with inadequate controls, creating data protection and operational security exposure." },
{ id:20542, domain:3, level:3, question:"During a review of software development practices, an IS auditor discovers that developers have access to production data in the development environment. What is the PRIMARY control concern?", options:["Development will be slower without real data","Exposing production data (potentially including personal or sensitive information) in development environments violates data protection principles and creates confidentiality, regulatory, and privacy risk","Developers prefer real data for testing","Development environments are always less secure"], correct:1, explanation:"Using production data in development environments violates data minimization and privacy principles, exposes sensitive data to a less-controlled environment, and may breach regulatory requirements such as GDPR or PCI DSS." },
{ id:20543, domain:3, level:1, question:"What is a 'Gantt chart' used for in project management?", options:["To document system requirements","To visually display project tasks, timelines, and dependencies","To track software defects","To record project costs"], correct:1, explanation:"A Gantt chart is a bar chart that visually represents project tasks, their durations, start and end dates, and dependencies, providing a timeline view of project scheduling." },
{ id:20544, domain:3, level:1, question:"Which of the following is a key output of the system design phase of the SDLC?", options:["Business case","System design specification","Project charter","User acceptance test results"], correct:1, explanation:"The system design specification (or design document) is the primary output of the design phase, describing how the system will be technically implemented to meet the requirements." },
{ id:20545, domain:3, level:1, question:"What does 'UAT' stand for in software testing?", options:["Unified Acceptance Testing","User Acceptance Testing","Universal Application Testing","Unsupported Application Troubleshooting"], correct:1, explanation:"UAT stands for User Acceptance Testing, the phase where business users validate that the system meets their requirements and is acceptable for production use." },
{ id:20546, domain:3, level:1, question:"Which control prevents a single person from both initiating and approving their own transactions in a system?", options:["Audit logging","Password controls","Segregation of duties","Data encryption"], correct:2, explanation:"Segregation of duties prevents one person from controlling an entire transaction by dividing incompatible tasks (such as initiation and approval) among different individuals." },
{ id:20547, domain:3, level:1, question:"In the context of software testing, what is a 'test case'?", options:["A document listing all defects found during testing","A specific set of conditions, inputs, and expected results designed to verify a particular system behavior","A summary of the overall test effort","A tool used to automate testing"], correct:1, explanation:"A test case specifies the exact conditions, input values, steps, and expected results used to verify that a particular aspect of system functionality works as intended." },
{ id:20548, domain:3, level:1, question:"What is 'system documentation' primarily used for during maintenance?", options:["To satisfy legal requirements only","To document user complaints","To provide technical reference information enabling developers and administrators to understand, maintain, and modify the system","To replace user training"], correct:2, explanation:"System documentation provides technical reference information about system architecture, design, interfaces, and code, enabling developers and administrators to understand and maintain the system over its lifetime." },
{ id:20549, domain:3, level:1, question:"Which development methodology is BEST suited for projects with well-defined, stable requirements?", options:["Agile Scrum","Extreme Programming (XP)","Waterfall","Kanban"], correct:2, explanation:"The waterfall methodology is most suitable when requirements are well-understood, stable, and unlikely to change, as its sequential phases work best with predictable, well-defined scope." },
{ id:20550, domain:3, level:1, question:"What is the purpose of 'escrow' in software acquisition contracts?", options:["To hold a copy of source code with a neutral third party, released if the vendor fails","To hold payment until the system is delivered","To provide a refund if the software does not work","To ensure compliance with software licensing"], correct:0, explanation:"Source code escrow places a copy of the application's source code with a neutral third-party escrow agent, to be released to the customer if the vendor goes out of business or fails to maintain the software." },
{ id:20551, domain:3, level:2, question:"An IS auditor is reviewing the testing phase of a large system implementation. Which finding represents the HIGHEST risk?", options:["Test scripts were reviewed by a third party","Test results are not formally documented or reviewed and approved by management","Users attended training sessions","Testing was conducted in a dedicated test environment"], correct:1, explanation:"Undocumented or unapproved test results mean there is no formal evidence that testing was adequately performed or that identified defects were resolved before deployment." },
{ id:20552, domain:3, level:2, question:"Which practice in secure coding prevents attackers from learning sensitive system information through error messages?", options:["Input validation","Password hashing","Proper error handling and generic error messages","Session management"], correct:2, explanation:"Proper error handling ensures that error messages shown to users do not reveal sensitive system information (stack traces, database details, internal paths) that could be exploited by attackers." },
{ id:20553, domain:3, level:2, question:"An IS auditor finds that a critical application has not been patched for 18 months because the patch process requires extensive regression testing. What is the MOST appropriate recommendation?", options:["Develop a risk-based patching approach that prioritizes critical security patches with streamlined testing, while maintaining full regression testing for major updates","Skip patch testing to speed up patching","Accept all vulnerabilities as residual risk","Outsource patch management to the vendor"], correct:0, explanation:"A risk-based patching approach prioritizes critical security patches with focused, expedited testing rather than full regression, balancing security urgency against operational stability." },
{ id:20554, domain:3, level:2, question:"Which type of software testing uses automated tools to analyze source code without executing it?", options:["Dynamic application security testing (DAST)","Static application security testing (SAST)","Penetration testing","Load testing"], correct:1, explanation:"Static application security testing (SAST) analyzes source code, bytecode, or binaries without executing the program, identifying potential vulnerabilities early in the development lifecycle." },
{ id:20555, domain:3, level:2, question:"An IS auditor is reviewing an organization's approach to managing third-party software components (open-source libraries). Which risk is MOST significant?", options:["Open-source software is always less functional","Third-party components may contain known vulnerabilities that are not tracked or updated, creating unmanaged security exposure in production applications","Third-party components require specialized programming languages","Open-source software has licensing costs"], correct:1, explanation:"Unmanaged third-party and open-source components are a major source of application vulnerability; organizations must track component versions and known vulnerabilities and update affected components promptly." },
{ id:20556, domain:3, level:2, question:"Which project management document formally records approved changes to project scope, schedule, or budget?", options:["Risk register","Change request/change order","Project charter","Project status report"], correct:1, explanation:"A change request or change order formally documents approved modifications to baseline project parameters (scope, schedule, budget), ensuring changes are authorized and impact-assessed." },
{ id:20557, domain:3, level:2, question:"In a software acquisition, what does 'functional testing' verify?", options:["Whether the software can handle extreme loads","Whether the software performs its specified functions correctly according to requirements","Whether the software meets performance benchmarks","Whether the software is free of security vulnerabilities"], correct:1, explanation:"Functional testing verifies that the software correctly performs all specified functions according to its requirements, checking that features work as intended under normal conditions." },
{ id:20558, domain:3, level:2, question:"What is the PRIMARY reason IS auditors review project steering committee minutes during a project audit?", options:["To assess developer performance","To verify project budget figures","To understand governance decisions, risk awareness, issue escalation, and management oversight of the project","To check attendance records"], correct:2, explanation:"Steering committee minutes reveal the governance quality of the project, including how risks were identified and managed, what decisions were made, and whether appropriate oversight was exercised." },
{ id:20559, domain:3, level:2, question:"Which control BEST ensures that output reports from a financial system are complete and accurate before distribution?", options:["User authentication requirements","Reconciliation of report totals to source data before distribution","Digital signatures on reports","Encryption of report files"], correct:1, explanation:"Reconciling report totals against source data before distribution ensures that reports accurately reflect the underlying data and that no records have been omitted or duplicated during report generation." },
{ id:20560, domain:3, level:2, question:"An organization is implementing an enterprise system and contracts with a vendor for implementation services. What control is MOST important to protect the organization if the project fails?", options:["Including clear contract terms with defined milestones, acceptance criteria, performance bonds, and termination provisions","Requiring weekly status reports","Requiring the vendor to use agile methodology","Assigning an internal project manager"], correct:0, explanation:"Strong contract terms with milestones, defined acceptance criteria, performance guarantees, and exit provisions protect the organization's interests and provide remedies if the vendor fails to deliver." },
{ id:20561, domain:3, level:2, question:"Which testing type verifies that a system can recover to a known good state after a failure?", options:["Regression testing","Security testing","Recovery testing","Load testing"], correct:2, explanation:"Recovery testing evaluates whether the system can successfully recover from failures, crashes, or hardware problems and return to a known, correct operational state within acceptable timeframes." },
{ id:20562, domain:3, level:2, question:"What is the MAIN risk of having no formal system for tracking and managing software defects?", options:["Testing will be completed too quickly","Defects may be forgotten, remain unresolved in production, or be fixed inconsistently, without accountability or priority management","Developers will have too much work","Documentation will be excessive"], correct:1, explanation:"Without formal defect tracking, known problems may go unresolved, be duplicated, lack accountability, or be prioritized incorrectly, increasing the risk of defects remaining in production software." },
{ id:20563, domain:3, level:2, question:"Which consideration is MOST important when deciding between building a custom system versus purchasing a COTS solution?", options:["The vendor's marketing materials","Whether the organization's requirements are standard industry processes or truly unique competitive differentiators that justify custom development cost and risk","The number of users who will use the system","The programming language the vendor uses"], correct:1, explanation:"The build vs. buy decision should hinge on whether requirements are standard (COTS is appropriate) or truly differentiated (justifying custom development's higher cost and risk)." },
{ id:20564, domain:3, level:2, question:"An IS auditor reviews a system that processes financial transactions and finds no edit checks on transaction amounts. What is the PRIMARY risk?", options:["Transaction processing will be slow","Users will find the system difficult to use","Erroneous or fraudulent transaction amounts (including negative amounts or extreme values) may be processed, leading to financial loss or misstatement","Reporting will be affected"], correct:2, explanation:"Without edit checks on transaction amounts, the system could accept and process erroneous or fraudulent values (zero amounts, negative values, extreme amounts), creating financial integrity and fraud risk." },
{ id:20565, domain:3, level:2, question:"What is the PRIMARY purpose of 'code walkthroughs' or 'code inspections' in software quality assurance?", options:["To systematically review code with peers to identify defects, logic errors, and non-compliance with standards before testing","To demonstrate code to management","To document the code for maintenance","To train junior developers"], correct:0, explanation:"Code walkthroughs and inspections are structured peer reviews where developers examine code to find defects, logic errors, and standards violations before testing begins, at the least costly stage to fix them." },
{ id:20566, domain:3, level:1, question:"What does 'systems integration testing' (SIT) verify?", options:["That individual code modules work correctly in isolation","That different system components and external interfaces work correctly together as an integrated whole","That the system meets user acceptance criteria","That the system can handle peak loads"], correct:1, explanation:"Systems integration testing verifies that all integrated components, modules, and external system interfaces work together correctly, testing the interactions and data flows between parts." },
{ id:20567, domain:3, level:1, question:"Which project risk is indicated when a project's actual costs significantly exceed planned costs from early in the project?", options:["Scope creep is occurring","The project budget was underestimated or resource consumption is higher than planned","The project has too many team members","The project will be delivered early"], correct:1, explanation:"Early and significant cost overruns indicate that the original budget estimate was inaccurate or that resource consumption is higher than planned, signaling a project in financial distress." },
{ id:20568, domain:3, level:1, question:"What is the purpose of a 'vendor management' program?", options:["To reduce the number of vendors used by the organization","To oversee vendor relationships, performance, compliance, and risk on an ongoing basis","To negotiate lower prices from all vendors","To manage vendor employee assignments"], correct:1, explanation:"A vendor management program establishes processes for selecting, contracting, monitoring, and managing vendors to ensure they deliver contracted services, meet performance standards, and comply with requirements." },
{ id:20569, domain:3, level:1, question:"Which control is MOST effective at preventing unauthorized access to sensitive data output by a system?", options:["Ensuring all output is printed in color","Restricting output access based on user roles and need-to-know principles","Logging all report generation activities","Requiring all output to be reviewed by IT"], correct:1, explanation:"Role-based access control restricting output to users with a legitimate need-to-know is the most effective preventive control for protecting sensitive system output from unauthorized access." },
{ id:20570, domain:3, level:1, question:"What is the PRIMARY purpose of 'acceptance testing' in system acquisition?", options:["To formally verify that the system meets contractual and functional requirements before final acceptance and payment","To test the system under extreme load","To test individual code modules","To assess the vendor's development process"], correct:0, explanation:"Acceptance testing verifies that the delivered system meets the specified requirements and acceptance criteria before the organization formally accepts the system and authorizes final payment." },
{ id:20571, domain:3, level:2, question:"An IS auditor is reviewing a DevOps environment. Which control is MOST important to ensure quality and security gates are not bypassed in the deployment pipeline?", options:["Requiring developers to document deployments","Implementing automated, mandatory pipeline stages (code review, security scan, automated tests) that must pass before any deployment to production","Having operations staff approve all deployments verbally","Restricting deployment to certain days of the week"], correct:1, explanation:"Mandatory automated pipeline stages that must pass before deployment provide consistent, enforced quality and security gates that cannot be bypassed, compensating for the reduced manual oversight in DevOps." },
{ id:20572, domain:3, level:2, question:"What is the GREATEST benefit of including security requirements in the earliest stages of the SDLC?", options:["Security requirements can be ignored later","Security requirements make the project faster","Security issues are far cheaper to remediate during design than during testing or after deployment, and security is built in rather than bolted on","End users prefer secure systems"], correct:2, explanation:"The cost of fixing security defects increases dramatically at later stages; addressing security during design is many times cheaper than post-deployment remediation and results in inherently more secure systems." },
{ id:20573, domain:3, level:2, question:"An IS auditor reviewing a phased system rollout finds that each phase lacks defined rollback procedures. What is the PRIMARY risk?", options:["If a phase fails, the organization may be unable to quickly revert to the previous stable state, causing extended operational disruption","The rollout will take too long","Phases will overlap","Users will not be trained in time"], correct:0, explanation:"Without documented rollback procedures, a failed deployment phase may leave the organization without a reliable recovery path, extending the duration and impact of system failures during implementation." },
{ id:20574, domain:3, level:2, question:"Which technique is MOST effective for detecting duplicate transactions in a financial system?", options:["Random sampling","Automated matching of transaction attributes (date, amount, payee, reference) to identify duplicates using data analysis tools","Manual review of all transactions","Requiring two approvers for all transactions"], correct:1, explanation:"Automated matching of key transaction attributes across the full transaction population is the most effective technique for systematically identifying duplicate entries that may otherwise be missed in sampling or manual review." },
{ id:20575, domain:3, level:2, question:"An IS auditor is assessing an organization's software development lifecycle and finds no formal process for managing requirements changes. What is the PRIMARY risk?", options:["Developers will work too slowly","Uncontrolled requirement changes lead to scope creep, unpredictable system behavior, untested functionality, and inability to demonstrate that all requirements were implemented and tested","The project will finish early","Documentation will be excessive"], correct:1, explanation:"Without change control for requirements, scope creep introduces unverified features, untested changes may enter production, and there is no baseline to demonstrate complete and tested implementation." },
{ id:20576, domain:3, level:3, question:"An IS auditor discovers that an organization routinely marks high-risk changes as 'emergency changes' to bypass the standard approval process. Over the past year, 35% of all changes used the emergency path. What is the MOST significant finding?", options:["Emergency changes are being processed too quickly","The emergency change process is being systematically abused to circumvent change management controls, eliminating the risk assessment and approval safeguards that protect production stability","Changes are being implemented too frequently","The change advisory board is too slow"], correct:1, explanation:"When emergency changes constitute a significant fraction of all changes, it indicates systematic bypass of controls; emergency processes are designed for rare, genuine emergencies, not routine high-risk changes, and this pattern represents a fundamental control failure." },
{ id:20577, domain:3, level:3, question:"An IS auditor is reviewing application controls for a payroll system and finds that the system allows retroactive changes to pay rates with no additional authorization requirement or flagging. What is the PRIMARY risk?", options:["Payroll processing will be slower","Unauthorized retroactive pay rate changes could be used to commit payroll fraud without detection, as they would not trigger normal authorization workflows","Reports may be generated incorrectly","End users may make errors"], correct:1, explanation:"Retroactive pay rate changes are a high-risk transaction type that could facilitate fraud; they should require additional authorization beyond standard pay rate changes and be automatically flagged for management review." },
{ id:20578, domain:3, level:3, question:"An organization is implementing a machine learning model to automate credit approval decisions. What is the PRIMARY control concern from an IS audit perspective?", options:["The model will be too expensive to operate","The model may make biased or unexplainable decisions, and without controls for model validation, bias testing, explainability, and human override, the organization faces regulatory, ethical, and financial risk","Machine learning models are always accurate","The model will require too much data"], correct:1, explanation:"Automated decision models introduce risk of biased outcomes, regulatory non-compliance (fair lending laws require explainable decisions), and undetected errors; robust model governance including validation, bias testing, explainability, and override capability is essential." },
{ id:20579, domain:3, level:3, question:"An IS auditor reviewing a system acquisition finds that the business case was prepared entirely by the IT department without business unit input. What is the PRIMARY governance concern?", options:["IT may overestimate technical complexity","Business benefits may be overstated or misrepresented without business validation, and without business ownership, benefit realization accountability is unclear, undermining governance integrity","The business case will be too short","IT will take too long to implement the system"], correct:1, explanation:"Business cases prepared without business unit involvement risk overstating benefits, understating operational impact, and lacking business ownership—all of which undermine governance and accountability for benefit realization." },
{ id:20580, domain:3, level:3, question:"An IS auditor finds that an organization's software supply chain includes many open-source components with no tracking of versions or known vulnerabilities. What is the MOST significant risk?", options:["Known, publicly disclosed vulnerabilities in untracked open-source components may exist in production systems without the organization's knowledge, providing attackers with easy exploitation paths","Open-source software requires licensing fees","Open-source software is less functional","Open-source components are difficult to integrate"], correct:0, explanation:"Untracked open-source components mean publicly known vulnerabilities (CVEs) may exist in production, and since attackers can identify affected versions, organizations with no software bill of materials (SBOM) cannot prioritize remediation of critical vulnerabilities." },
{ id:20581, domain:3, level:3, question:"During a review of a cloud-native application development program, an IS auditor finds that infrastructure is provisioned through code (Infrastructure as Code) without a review or approval process. What is the PRIMARY risk?", options:["Infrastructure provisioning will be too slow","Unreviewed infrastructure code can introduce misconfigurations, security vulnerabilities, or unauthorized resources into production environments, bypassing traditional change management controls","Cloud infrastructure is always secure by default","The development team will not understand the infrastructure"], correct:1, explanation:"Infrastructure as Code changes carry the same risk as application code changes and require equivalent review and approval processes; unreviewed IaC changes can deploy misconfigured, insecure, or unauthorized infrastructure at scale." },
{ id:20582, domain:3, level:3, question:"An IS auditor assessing a system implementation project finds that the project manager has been reporting green status on all metrics for six months, but the project is now six months behind schedule and significantly over budget. What does this MOST likely indicate?", options:["The project manager lacks technical skills","Status reporting controls are ineffective, enabling management to be misled about project health; either reporting mechanisms are inadequate, oversight is insufficient, or the project manager is deliberately misrepresenting status","The budget was insufficient from the start","The project had unexpected technical complexity"], correct:1, explanation:"Persistent optimistic status reporting that does not reflect actual performance indicates a governance failure—either inadequate status verification mechanisms, insufficient oversight, or deliberate misrepresentation, all of which represent serious project control weaknesses." },
{ id:20583, domain:3, level:2, question:"Which control BEST ensures that system configuration changes are documented and authorized before implementation?", options:["Automated configuration scanning","A configuration management database (CMDB) combined with a formal change approval process","Requiring developers to sign off on changes","Performing annual configuration audits"], correct:1, explanation:"A CMDB records the current and baseline state of configuration items, and combined with formal change approval, ensures all configuration changes are authorized, documented, and traceable." },
{ id:20584, domain:3, level:2, question:"An IS auditor reviews a software project and finds that testers are reporting defects but developers are closing them as 'not a bug' without resolution or management review. What is the PRIMARY concern?", options:["Developers are working too slowly","Testing is progressing normally","Defects may be improperly closed without genuine resolution, and without independent management oversight, significant issues may reach production","The defect log will be too long"], correct:2, explanation:"Developers unilaterally closing defects without resolution or oversight creates risk that real defects are suppressed rather than fixed, potentially allowing significant issues to reach production unchallenged." },
{ id:20585, domain:3, level:2, question:"What is the PRIMARY risk when an organization uses the same data in development, test, and production environments?", options:["Testing will not be realistic enough","Production data (potentially including PII or other sensitive data) is exposed in less-controlled environments, creating privacy, regulatory, and confidentiality risk","Developers will not understand the system","Data volumes will be insufficient for testing"], correct:1, explanation:"Using production data in development or test environments exposes sensitive data (personal information, financial data) to less-controlled environments with broader access, creating privacy breaches and regulatory compliance violations." },
{ id:20586, domain:3, level:1, question:"What does 'PRINCE2' stand for?", options:["Project Requirements in a Controlled Environment 2nd Edition","Projects IN Controlled Environments 2","Project Risk Initiative for New Controlled Environments Edition 2","Professional Risk and Integrated Network for Controlled Environments 2"], correct:1, explanation:"PRINCE2 stands for Projects IN Controlled Environments 2, a structured project management methodology widely used in government and industry, particularly in the UK." },
{ id:20587, domain:3, level:1, question:"Which of the following BEST describes a 'critical path' in project management?", options:["The most technically challenging tasks in the project","The sequence of tasks that determines the minimum project duration, where any delay directly delays project completion","The tasks with the highest budget allocation","The tasks assigned to the most experienced team members"], correct:1, explanation:"The critical path is the longest sequence of dependent tasks in a project, determining the minimum duration; any delay in a critical path task directly extends the overall project completion date." },
{ id:20588, domain:3, level:1, question:"What is the purpose of a 'release management' process in IT?", options:["To manage IT department staffing","To plan, schedule, and control the movement of releases through test and production environments","To release IT project budgets","To manage software licensing"], correct:1, explanation:"Release management governs the process of planning, scheduling, building, testing, and deploying releases of IT systems and services into production in a controlled and auditable manner." },
{ id:20589, domain:3, level:1, question:"Which control ensures that data processed by a system matches the data that was originally entered?", options:["Output distribution controls","Processing controls including control totals and reconciliation","Access controls","Physical security controls"], correct:1, explanation:"Processing controls, including control totals, record counts, and reconciliation, verify that data processed by the system matches what was originally entered, ensuring processing integrity." },
{ id:20590, domain:3, level:1, question:"What is 'cross-site scripting' (XSS) in application security?", options:["A technique for transferring data between servers","A legitimate data sharing method between websites","An attack where malicious scripts are injected into web pages viewed by other users","A form of database attack"], correct:2, explanation:"Cross-site scripting (XSS) is an injection attack where malicious scripts are inserted into web application pages, executing in victims' browsers to steal session tokens, redirect users, or perform actions on their behalf." },
{ id:20591, domain:3, level:1, question:"Which phase of the SDLC involves maintaining the system after it has been deployed to production?", options:["Requirements","Design","Testing","Maintenance/operations"], correct:3, explanation:"The maintenance or operations phase follows deployment and involves ongoing support, bug fixes, performance monitoring, and enhancements to the system during its operational life." },
{ id:20592, domain:3, level:2, question:"An IS auditor is reviewing an ERP implementation project's training plan. Which finding represents the GREATEST risk to successful implementation?", options:["Training materials were developed by an external consultant","End users will not receive training until after the system goes live","Training is scheduled over multiple sessions","Training includes both classroom and online components"], correct:1, explanation:"Providing training after go-live means users will operate the new system without adequate knowledge, leading to errors, workarounds, and productivity losses that could compromise data integrity and business operations." },
{ id:20593, domain:3, level:2, question:"Which risk is MOST associated with using agile development for a system subject to strict regulatory compliance requirements?", options:["Agile projects cost more","The iterative nature of agile may result in incomplete documentation and compliance evidence, making it difficult to demonstrate regulatory compliance to auditors or regulators","Regulatory requirements change too frequently for agile","Agile teams work too quickly"], correct:1, explanation:"Agile's lightweight documentation approach can conflict with regulatory requirements for comprehensive documentation and traceability; organizations must adapt agile practices to ensure compliance evidence is systematically captured." },
{ id:20594, domain:3, level:2, question:"What is the PRIMARY purpose of an 'information security assessment' during system acquisition?", options:["To evaluate vendor pricing","To identify security risks in the proposed solution and verify that adequate security controls are planned before acquisition is finalized","To assess the vendor's HR practices","To evaluate the system's user interface design"], correct:1, explanation:"A security assessment during acquisition identifies security risks in the proposed solution and verifies that adequate controls are designed in, while it is still cost-effective to address them before deployment." },
{ id:20595, domain:3, level:2, question:"Which development approach is MOST appropriate when requirements are expected to evolve significantly during the project?", options:["Traditional waterfall","PRINCE2 waterfall variant","Iterative or agile methodology","Big design upfront"], correct:2, explanation:"Iterative and agile methodologies are designed for environments with evolving or uncertain requirements, delivering functionality incrementally and incorporating feedback to adapt to changing needs." },
{ id:20596, domain:3, level:2, question:"An IS auditor is reviewing an organization's software testing strategy and finds that only positive test cases are used. What is the PRIMARY risk?", options:["Testing will take too long","Without negative testing (testing invalid inputs and error conditions), the system's behavior under invalid or malicious input is unknown, creating security and reliability risk","Positive testing is always sufficient","Users will not encounter errors"], correct:1, explanation:"Testing only with valid inputs leaves the system's behavior under invalid, boundary, or malicious inputs unknown; negative testing is essential for discovering how the system handles errors, edge cases, and potential attacks." },
{ id:20597, domain:3, level:2, question:"What is the MAIN benefit of using automated testing tools in a continuous integration pipeline?", options:["Automated tools are cheaper to license than testers","Tests are executed consistently and immediately after each code change, providing rapid feedback on regressions and quality issues","Automated tools can replace all human judgment in testing","Automated testing eliminates the need for any manual testing"], correct:1, explanation:"Automated testing in CI pipelines provides immediate, consistent feedback after every code change, catching regressions and defects early before they compound, far faster than manual testing cycles allow." },
{ id:20598, domain:3, level:2, question:"An IS auditor reviewing an outsourced development project finds that intellectual property ownership is not clearly defined in the contract. What is the PRIMARY risk?", options:["The vendor will charge more","The project will be delivered late","The organization may not own the software it has paid for, creating legal, operational, and competitive risk if the vendor claims or shares the IP","The vendor will use open-source components"], correct:2, explanation:"Ambiguous IP ownership can result in the vendor retaining rights to custom-developed software, potentially limiting the organization's ability to modify, resell, or transfer the software, and creating serious legal and operational exposure." },
{ id:20599, domain:3, level:3, question:"An IS auditor is assessing a financial institution's system development process and finds that developers in multiple countries committed code without any branch protection rules or peer review requirements enforced in the repository. What is the MOST significant control risk?", options:["International time zones make collaboration difficult","Without enforced branch protection and mandatory code review, any developer can commit arbitrary code to the production branch, bypassing quality, security, and change control gates, creating high risk of unauthorized or malicious code entering production","Multiple developers working simultaneously will cause performance issues","Code may not compile correctly"], correct:1, explanation:"Unprotected repositories without mandatory review allow any contributor to push code directly to protected branches, eliminating the last technical control preventing unauthorized or malicious code from entering production systems." },
{ id:20600, domain:3, level:3, question:"An IS auditor is reviewing an agile program delivering multiple interdependent systems simultaneously. Which governance gap is MOST concerning from a program-level perspective?", options:["Individual sprint teams work independently","There is no program-level integration testing or cross-team coordination mechanism, meaning integration risks between systems are not identified or managed until deployment","Sprint ceremonies take too long","Teams use different agile tools"], correct:1, explanation:"When multiple interdependent systems are developed simultaneously without program-level integration testing and coordination, integration failures, interface incompatibilities, and data consistency issues are likely to be discovered only during deployment when remediation is most expensive." },
{ id:20601, domain:3, level:1, question:"What is the main purpose of a 'walk-through test' during system implementation?", options:["To test system performance","To verify that a transaction can be traced completely through the system from input to output, confirming controls operate as described","To verify network connectivity","To test system security"], correct:1, explanation:"A walk-through test traces a transaction end-to-end through the system to verify that all controls operate as described and that the transaction is correctly processed at each stage." },
{ id:20602, domain:3, level:1, question:"Which of the following represents an output control in an application system?", options:["User login authentication","Data validation during input","Control totals on printed reports to verify completeness","Encryption of data in transit"], correct:2, explanation:"Control totals on printed reports are output controls that verify that the data contained in reports is complete and accurate, matching the source data processed by the system." },
{ id:20603, domain:3, level:1, question:"What does 'interoperability' mean in the context of system acquisition?", options:["The ability of different systems to exchange and use information with each other","The ability of the system to operate without maintenance","The speed at which the system processes transactions","The system's ability to scale to more users"], correct:0, explanation:"Interoperability refers to the ability of different systems, applications, or components to communicate, exchange data, and work together effectively." },
{ id:20604, domain:3, level:1, question:"Which risk is MOST associated with using open-source software components in a commercial application?", options:["Open-source software is always insecure","Unmanaged vulnerabilities in open-source components may be exploited, and licensing terms may create legal obligations if not properly managed","Open-source software cannot be customized","Open-source software requires expensive licenses"], correct:1, explanation:"Open-source components carry two primary risks: security vulnerabilities that must be tracked and patched, and license compliance obligations (some licenses require releasing derivative work) that must be understood and honored." },
{ id:20605, domain:3, level:1, question:"What is the purpose of a 'test summary report' at the end of the testing phase?", options:["To document all code changes made during testing","To summarize testing activities, results, defects found and resolved, and provide a recommendation on system readiness for deployment","To list all test cases that were planned","To document the testing schedule"], correct:1, explanation:"A test summary report consolidates testing results, provides metrics on defects found and resolved, assesses test coverage, and gives a formal recommendation on whether the system is ready for production deployment." },
{ id:20606, domain:3, level:2, question:"An IS auditor reviewing a software project finds that the requirements specification was signed off by only the IT project manager, with no business owner signature. What is the PRIMARY risk?", options:["The requirements document will be too long","Business requirements may not accurately reflect actual business needs, as IT may have interpreted or filtered requirements without sufficient business validation and ownership","IT may build the wrong architecture","The project will be delivered late"], correct:1, explanation:"Requirements signed off only by IT lack business validation and ownership; business users may dispute whether the delivered system meets their needs, and there is no business accountability for requirement accuracy." },
{ id:20607, domain:3, level:2, question:"What control BEST prevents unauthorized software from being installed on production systems?", options:["Annual software audits","Application whitelisting that only permits authorized, approved software to execute on production systems","Requiring users to request software through IT helpdesk","Logging all software installation attempts"], correct:1, explanation:"Application whitelisting is a proactive preventive control that technically prevents unauthorized software from executing, unlike reactive controls (audits, logging) that only detect unauthorized software after the fact." },
{ id:20608, domain:3, level:2, question:"An organization is conducting a build vs. buy analysis. Which scenario MOST strongly favors building custom software?", options:["The organization's requirements closely match a commercially available product","The budget for development is limited","The organization's process is a unique competitive differentiator where no COTS product exists and customization is infeasible","The project timeline is very short"], correct:2, explanation:"Custom development is most justified when the business process is a genuine competitive differentiator with unique requirements that cannot be adequately served by any available COTS product." },
{ id:20609, domain:3, level:2, question:"Which control BEST ensures that software released to production is exactly what was tested and approved?", options:["Requiring developers to sign a release checklist","Comparing cryptographic hashes of software packages in test and production environments to verify integrity","Testing the software again after deployment","Having a manager visually review the release"], correct:1, explanation:"Cryptographic hash comparison provides mathematical proof that the software deployed to production is identical to what was tested and approved, detecting any unauthorized modification during the release process." },
{ id:20610, domain:3, level:2, question:"An IS auditor is reviewing a project that significantly exceeded its original timeline. Which project artifact would BEST help determine the root cause?", options:["The project charter","The risk register and issue log reviewed alongside project milestone completion records","The final test results","The business case"], correct:1, explanation:"Comparing the risk register and issue log against milestone completion history reveals what risks materialized, when problems were identified, whether they were anticipated, and how they were managed—directly revealing root causes of delays." },
{ id:20611, domain:3, level:1, question:"Which of the following BEST describes 'functional requirements'?", options:["Requirements describing how fast the system must perform","Requirements describing how secure the system must be","Requirements describing what the system must do — the specific behaviors and functions it must support","Requirements describing how many users must be supported"], correct:2, explanation:"Functional requirements define what a system must do — the specific behaviors, functions, and capabilities that the system must provide to meet user and business needs." },
{ id:20612, domain:3, level:1, question:"What is 'non-functional requirements' in system development?", options:["Requirements that are not important to the project","Requirements describing system quality attributes such as performance, availability, security, and scalability","Requirements that developers choose not to implement","Requirements added after go-live"], correct:1, explanation:"Non-functional requirements define quality attributes and operational constraints the system must meet, including performance, reliability, availability, scalability, maintainability, and security." },
{ id:20613, domain:3, level:1, question:"Which element is MOST critical for effective project governance?", options:["Large project budget","Having a dedicated project management office","Clear accountability structures, decision-making authority, and regular status reporting to appropriate stakeholders","Using a specific project management methodology"], correct:2, explanation:"Effective project governance requires clearly defined accountability, appropriate decision authority at each level, and transparent reporting so stakeholders can make informed decisions and maintain oversight." },
{ id:20614, domain:3, level:1, question:"What is a 'risk register' in project management?", options:["A list of all project team members","A document that identifies, describes, and tracks potential risks along with their probability, impact, and mitigation actions","A budget tracking spreadsheet","A list of completed project deliverables"], correct:1, explanation:"A risk register is a project management tool that catalogs identified risks, assesses their probability and impact, documents mitigation strategies and owners, and tracks risk status throughout the project." },
{ id:20615, domain:3, level:1, question:"Which acquisition document is used to solicit vendor pricing for specific goods or services with defined specifications?", options:["RFP (Request for Proposal)","RFI (Request for Information)","RFQ (Request for Quotation)","SOW (Statement of Work)"], correct:2, explanation:"An RFQ (Request for Quotation) solicits specific pricing from vendors for defined goods or services, as opposed to an RFP which invites vendors to propose broader solutions." },
{ id:20616, domain:3, level:2, question:"An IS auditor reviewing IT project portfolio management finds that projects are approved without linking them to strategic objectives. What is the PRIMARY governance concern?", options:["Projects may exceed their budgets","IT investment may not be aligned with organizational strategy, resulting in resources spent on projects that do not advance strategic goals","Project managers may not be qualified","Project timelines may not be accurate"], correct:1, explanation:"Without linkage to strategic objectives, IT project approval lacks a strategic filter, risking investment in projects that consume resources without advancing organizational goals—a fundamental IT governance failure." },
{ id:20617, domain:3, level:2, question:"Which testing approach involves providing random, unexpected, or invalid inputs to identify system crashes or unexpected behavior?", options:["Regression testing","Fuzz testing (fuzzing)","UAT","Load testing"], correct:1, explanation:"Fuzz testing involves providing large amounts of random, malformed, or unexpected data as input to discover crashes, memory leaks, and unexpected behaviors that indicate security vulnerabilities or reliability issues." },
{ id:20618, domain:3, level:2, question:"An IS auditor finds that emergency production changes are routinely implemented without any post-implementation review or documentation update. What is the MOST significant risk?", options:["The configuration and documentation baseline becomes inaccurate, system state is unknown, and unauthorized changes may persist without detection or accountability","Emergency changes take too long","Change documentation takes too long to complete","Emergency changes are always successful"], correct:0, explanation:"Unreviewed and undocumented emergency changes corrupt the configuration baseline, create unknown system states, prevent root cause analysis, and may allow unauthorized changes to persist in production." },
{ id:20619, domain:3, level:2, question:"What is the PRIMARY benefit of using a 'software bill of materials' (SBOM) in application development?", options:["It reduces software development costs","It provides a comprehensive inventory of software components and dependencies, enabling rapid identification and remediation of vulnerable components when new vulnerabilities are disclosed","It eliminates the need for security testing","It automates software deployment"], correct:1, explanation:"An SBOM provides a complete, machine-readable inventory of all software components and dependencies, enabling organizations to quickly identify systems affected by newly disclosed vulnerabilities and prioritize remediation." },
{ id:20620, domain:3, level:2, question:"During a review of system acquisition, an IS auditor finds that the organization did not conduct reference checks with other customers of the selected vendor. What is the PRIMARY risk?", options:["The acquisition will cost more","The organization may have underestimated risks related to vendor delivery capability, support quality, and implementation challenges that existing customers have experienced","Other customers may not be in the same industry","Reference checks take too long"], correct:1, explanation:"Without reference checks, the organization misses direct evidence of vendor delivery capability and support quality from customers who have experienced the vendor in practice, potentially overlooking significant implementation or support risks." },
{ id:20621, domain:3, level:3, question:"An IS auditor is reviewing a large government IT acquisition and finds that the requirements in the RFP were written so specifically that only one vendor's product could meet them. What is the PRIMARY concern?", options:["The requirements are too detailed","Overly specific requirements designed to match one vendor's product suggest a lack of competitive procurement integrity, potential for favoritism, and may violate procurement regulations requiring fair competition","The requirements are technically complex","The RFP is too long"], correct:1, explanation:"Requirements written to fit a specific vendor's product indicate rigged procurement, violating fair competition principles, potentially breaching procurement regulations, and creating accountability and value-for-money concerns." },
{ id:20622, domain:3, level:3, question:"An IS auditor reviewing an AI-assisted code generation project finds that developers routinely accept AI-generated code without review. What is the PRIMARY risk?", options:["AI-generated code may contain security vulnerabilities, logic errors, or license-encumbered code that, without human review, enters production unchecked, bypassing normal quality and security gates","AI-generated code is always optimal","AI generates code too slowly","Developers prefer AI-generated code"], correct:0, explanation:"AI code generation tools can produce plausible-looking but insecure, incorrect, or license-conflicting code; accepting outputs without review bypasses critical security and quality controls just as copying unreviewed code from any untrusted source would." },
{ id:20623, domain:3, level:3, question:"An IS auditor is reviewing a microservices architecture that has grown to over 200 services managed by different teams. What is the PRIMARY governance concern?", options:["Too many services reduce performance","With 200+ independently deployed services managed by multiple teams, there is high risk that change management, security patching, configuration standards, and API governance are fragmented and inconsistent, creating systemic risk exposure","Microservices are always harder to develop","Testing microservices is always more difficult"], correct:1, explanation:"Large microservice estates with independent team ownership create governance fragmentation risk: inconsistent security controls, patch levels, configuration standards, and API changes can create enterprise-wide vulnerabilities that are difficult to detect and manage centrally." },
{ id:20624, domain:3, level:3, question:"An IS auditor assessing a critical financial system discovers that the system has no automated controls to detect or prevent transactions that deviate significantly from established patterns (e.g., unusually large amounts, off-hours processing). What is the MOST significant risk this represents?", options:["Transaction processing will be slower","The absence of anomaly detection controls means that unusual transactions indicative of error or fraud will not be automatically flagged for review, increasing the risk of undetected financial misstatement or loss","Off-hours processing has always occurred","Some legitimate transactions may be large"], correct:1, explanation:"Financial systems handling material transactions should have automated anomaly detection to flag unusual activity for human review; without this, fraudulent or erroneous transactions that fall outside normal patterns may go undetected until significant loss has occurred." },
{ id:20625, domain:3, level:3, question:"An IS auditor reviewing a SaaS acquisition finds that the contract permits the vendor to analyze customer data to improve their service. What is the PRIMARY privacy and security risk?", options:["The vendor will have access to system performance data","Service improvements benefit the customer","Customer data (potentially including personal, financial, or sensitive business information) may be used by the vendor beyond its original purpose, creating privacy breaches, regulatory violations, and competitive intelligence risk","The vendor needs data to provide the service"], correct:2, explanation:"Contractual provisions allowing vendors to use customer data for their own purposes (service improvement, analytics, model training) create serious privacy, confidentiality, and regulatory risk — customer data used beyond its intended purpose may breach privacy regulations and expose sensitive business information." },
{ id:20626, domain:3, level:2, question:"Which application control BEST detects when records have been deleted from a database table?", options:["Range checks on input fields","Monitoring sequence numbers for gaps that indicate deleted records","User authentication controls","Encryption of database fields"], correct:1, explanation:"Monitoring sequence numbers for gaps in sequentially numbered records detects deletions that would create breaks in the sequence, alerting administrators to potential unauthorized record deletion." },
{ id:20627, domain:3, level:2, question:"An IS auditor finds that an organization's system development standards document has not been updated in five years, and several sections are inconsistent with current technology and practices. What is the PRIMARY risk?", options:["Developers will spend time reading the document","Outdated standards may lead developers to follow obsolete practices, fail to implement required security controls for modern threats, or create false assurance that development follows current best practices","Standards documents are rarely used","The document is too long"], correct:1, explanation:"Outdated development standards create risk that developers follow obsolete guidance, miss current security and quality requirements, and that management has false assurance that development practices are adequate for modern threats and technologies." },
{ id:20628, domain:3, level:2, question:"What is the MOST important control when transitioning from a legacy system to a new system to ensure data integrity?", options:["Conducting user training before migration","Comprehensive data reconciliation comparing source and target data counts, amounts, and samples before decommissioning the legacy system","Migrating data during off-peak hours","Having the vendor perform the migration"], correct:1, explanation:"Comprehensive data reconciliation—verifying that all records migrated completely and accurately before decommissioning the legacy system—is the critical control ensuring data integrity and the ability to detect and correct migration errors." },
{ id:20629, domain:3, level:1, question:"Which of the following represents a preventive application control?", options:["Error reports identifying failed transactions","Audit logs of all transactions","Format validation that rejects invalid input before processing","Management review of exception reports"], correct:2, explanation:"Format validation that rejects invalid input before it enters the system is a preventive control, stopping errors from occurring rather than detecting them after the fact." },
{ id:20630, domain:3, level:1, question:"What is the purpose of 'software quality metrics' in development projects?", options:["To measure developer job satisfaction","To calculate software licensing costs","To quantify aspects of software quality (defect density, code coverage, complexity) to provide objective evidence of quality and guide improvement","To measure network performance"], correct:2, explanation:"Software quality metrics provide objective, quantitative measures of code quality, defect rates, test coverage, and complexity, enabling management to assess quality levels and make data-driven improvement decisions." },
{ id:20631, domain:3, level:1, question:"Which acquisition approach involves using a third party to build and operate a system on behalf of the organization?", options:["Custom in-house development","Build-operate-transfer (BOT) or outsourced development","COTS acquisition","Open-source implementation"], correct:1, explanation:"Build-operate-transfer and outsourced development arrangements involve a third party developing and operating the system, often with the option to transfer ownership or operation back to the organization later." },
{ id:20632, domain:3, level:1, question:"What does 'technical feasibility' assess in a system acquisition study?", options:["Whether the project budget is sufficient","Whether users will accept the new system","Whether the required technology exists and the organization has the technical capability to implement it","Whether the project timeline is realistic"], correct:2, explanation:"Technical feasibility assesses whether the technology required to build the proposed system exists, is mature enough for production use, and whether the organization has or can acquire the technical skills to implement and support it." },
{ id:20633, domain:3, level:2, question:"An IS auditor finds that a web application stores user session tokens in URLs rather than secure cookies. What is the PRIMARY security risk?", options:["URL session tokens are easier to use","Session tokens in URLs may be logged in server logs, browser history, and referrer headers, and shared when users copy URLs, enabling session hijacking","URLs are always encrypted","Session tokens in URLs expire faster"], correct:1, explanation:"Session tokens in URLs are exposed in multiple insecure locations (logs, browser history, referrer headers) and can be inadvertently shared, enabling attackers to hijack sessions — a well-known and serious web application security flaw." },
{ id:20634, domain:3, level:2, question:"Which control BEST ensures continuity of a critical system during a planned upgrade?", options:["Informing users about the upgrade","Testing the upgrade in a lower environment and maintaining rollback capability with defined rollback criteria and time limits","Completing the upgrade as quickly as possible","Having senior management approve the upgrade"], correct:1, explanation:"Testing upgrades in lower environments, preparing rollback procedures, and defining rollback criteria ensure that if an upgrade fails in production, there is a tested, time-limited recovery path to restore the previous stable state." },
{ id:20635, domain:3, level:2, question:"What is the PRIMARY benefit of including IS auditors in system development projects during the requirements and design phases?", options:["IS auditors can write better code","IS auditors will help deliver the project faster","IS auditors can identify control requirements and ensure controls are designed into the system from the start, when they are cheapest to implement","IS auditors can replace business analysts"], correct:2, explanation:"Early audit involvement ensures that control, audit trail, and compliance requirements are identified and built into system design from the beginning, avoiding costly retrofit of controls after deployment." },
{ id:20636, domain:3, level:3, question:"An IS auditor is reviewing a large-scale digital transformation program with 15 interdependent projects. Which program-level control is MOST critical?", options:["Ensuring all projects use the same agile methodology","A program-level integration management office with authority to coordinate dependencies, manage cross-project risks, and ensure cohesive architectural governance across all projects","Using a single vendor for all projects","Having the same project manager for all projects"], correct:1, explanation:"Large transformation programs with interdependent projects require a central integration function with authority to manage dependencies, architectural consistency, and cross-project risks — without this, local optimization creates systemic integration failures." },
{ id:20637, domain:3, level:3, question:"An IS auditor is reviewing a critical system where the vendor holds all source code and has full remote access for maintenance. The vendor recently experienced a data breach. What is the PRIMARY risk to assess?", options:["The system may need to be replaced","The vendor's compromised access credentials or infrastructure may enable unauthorized access to the organization's production environment through vendor remote access channels, representing an active supply chain security threat","The system will be unavailable","The vendor will increase support costs"], correct:1, explanation:"A vendor with remote production access that has been breached represents an immediate supply chain security threat; attackers may use compromised vendor credentials or infrastructure to pivot into the organization's production environment." },
{ id:20638, domain:3, level:3, question:"An IS auditor reviewing a cloud migration project finds that the organization has not defined data residency requirements in the cloud service contract. What is the PRIMARY risk?", options:["Cloud storage will cost more","Data may be stored or processed in jurisdictions subject to different legal requirements, enforcement actions, or government access powers than the organization intended, creating regulatory and sovereignty risk","Data residency does not affect security","Cloud providers always store data locally"], correct:1, explanation:"Without contractual data residency controls, cloud providers may store or process data in any jurisdiction, potentially subjecting it to foreign laws, government access orders, or regulatory requirements incompatible with the organization's obligations." },
{ id:20639, domain:3, level:3, question:"An IS auditor is assessing an organization that deploys software through a fully automated CI/CD pipeline with no manual approval step before production deployment. What is the PRIMARY control concern?", options:["Without a mandatory human approval gate before production deployment, there is no opportunity for human judgment to override automated processes when circumstances require it, and any failure in automated controls immediately affects production","Automated pipelines are too slow","Automated pipelines reduce quality","Developers prefer manual deployment"], correct:0, explanation:"Fully automated pipelines without human approval gates rely entirely on automated controls; if automated checks have gaps, are misconfigured, or are bypassed, changes flow directly to production without human oversight, removing the last line of defense." },
{ id:20640, domain:3, level:3, question:"An IS auditor concludes a review of an organization's complete system acquisition and development lifecycle. Which single finding would be MOST indicative of a mature, well-controlled development organization?", options:["The organization uses the most modern programming languages","Security, quality, and control requirements are systematically integrated at every SDLC phase, verified through automated and independent testing, with full traceability from business requirements through to tested production systems","The organization has a large QA team","All projects are delivered on time"], correct:1, explanation:"A mature development organization embeds security, quality, and control requirements throughout the SDLC, uses automation and independence to verify them, and maintains full traceability — this holistic, built-in approach is the hallmark of effective IS governance in development." }
];
